const session = $('Fetch Intent Session').first().json;
const orgDoc = $('Fetch Org Doc').first().json;
const trigger = $('Execute Workflow Trigger').first().json;
const messageSource = trigger.messageSource;
const userInput = trigger.userInput;
console.log("session", session)
const intent = (orgDoc.intents || []).find(i => i.name === session.intentName);
if (!intent) throw new Error('Intent not found: ' + session.intentName);

const repeatConfig = intent.repeatSections?.[session.sectionName];
if (!repeatConfig) throw new Error('Repeat section not found: ' + session.sectionName);

const subParams = repeatConfig.parameters || [];
let completedItems, currentItem, genQuestions;
try { completedItems = typeof session.completedItems === 'string' ? JSON.parse(session.completedItems) : (session.completedItems || []); } catch(e) { completedItems = []; }
try { currentItem = typeof session.currentItem === 'string' ? JSON.parse(session.currentItem) : (session.currentItem || {}); } catch(e) { currentItem = {}; }
try { genQuestions = session.generatedQuestions ? (typeof session.generatedQuestions === 'string' ? JSON.parse(session.generatedQuestions) : session.generatedQuestions) : null; } catch(e) { genQuestions = null; }

const fieldIndex = session.currentFieldIndex || 0;
const cycle = session.currentCycle || 1;

// ENTERING REPEAT — first time (from WF4)
if (messageSource === 'entering_repeat') {
  return [{ json: {
    action: genQuestions ? 'ask_next_field' : 'generate_questions',
    nextField: subParams[0],
    nextFieldIndex: 0,
    updatedSession: { ...session, currentFieldIndex: 0, currentItem: '{}', currentCycle: 1 },
    subParams, repeatConfig, genQuestions, completedItems, currentItem: {}
  }}];
}

// REPEAT YES — add another
if (messageSource === 'repeat_yes') {
  completedItems.push(currentItem);
  return [{ json: {
    action: 'ask_next_field',
    nextField: subParams[0],
    nextFieldIndex: 0,
    updatedSession: { ...session, currentCycle: cycle + 1, currentFieldIndex: 0, currentItem: '{}', completedItems: JSON.stringify(completedItems) },
    subParams, repeatConfig, genQuestions, completedItems, currentItem: {}
  }}];
}

// REPEAT NO — done collecting
if (messageSource === 'repeat_no') {
  completedItems.push(currentItem);
  // Merge pre-repeat fields with repeat array
  let preFields = {};
  try { preFields = typeof session.collectedFields === 'string' ? JSON.parse(session.collectedFields) : (session.collectedFields || {}); } catch(e) {}
  preFields[session.sectionName] = completedItems;
  return [{ json: {
    action: 'repeat_complete',
    mergedCollectedFields: JSON.stringify(preFields),
    itemCount: completedItems.length,
    updatedSession: { ...session, phase: 'collecting', collectedFields: JSON.stringify(preFields), completedItems: JSON.stringify(completedItems), currentItem: '{}' }
  }}];
}

// SAFETY: if fieldIndex past all sub-fields, re-send continue
if (fieldIndex >= subParams.length) {
  return [{ json: {
    action: 'send_continue',
    updatedSession: { ...session, currentItem: JSON.stringify(currentItem), currentFieldIndex: fieldIndex },
    repeatConfig, genQuestions, completedItems, currentItem
  }}];
}

// USER ANSWERED A FIELD
const currentField = subParams[fieldIndex];
currentItem[currentField.name] = userInput;
const nextIndex = fieldIndex + 1;

if (nextIndex >= subParams.length) {
  // All sub-fields done for this cycle
  return [{ json: {
    action: 'send_continue',
    updatedSession: { ...session, currentItem: JSON.stringify(currentItem), currentFieldIndex: nextIndex },
    repeatConfig, genQuestions, completedItems, currentItem
  }}];
}

// More sub-fields
return [{ json: {
  action: 'ask_next_field',
  nextField: subParams[nextIndex],
  nextFieldIndex: nextIndex,
  updatedSession: { ...session, currentFieldIndex: nextIndex, currentItem: JSON.stringify(currentItem) },
  subParams, repeatConfig, genQuestions, completedItems, currentItem
}}];

const data = $('Repeat Logic').first().json;
const s = data.updatedSession;
return [{ json: {
  userId: s.userId, phoneNumber: s.phoneNumber, intentName: s.intentName,
  organizationId: s.organizationId, parentOrganizationId: s.parentOrganizationId,
  phase: 'collecting', currentMainIndex: s.currentMainIndex,
  sectionName: s.sectionName, currentCycle: s.currentCycle, currentFieldIndex: 0,
  completedItems: typeof s.completedItems === 'string' ? s.completedItems : JSON.stringify(s.completedItems || []),
  currentItem: '{}',
  collectedFields: data.mergedCollectedFields,
  generatedQuestions: typeof s.generatedQuestions === 'string' ? s.generatedQuestions : JSON.stringify(s.generatedQuestions || {}),
  createdAt: s.createdAt || new Date().toISOString()
} }];

const data = $('Repeat Logic').first().json;
return [{ json: { 
  responseType: '__repeat_done__', 
  repeatComplete: true,
  message: '' 
} }];

// Get data from either Question Gen path or direct path
let data;
try { data = $('Parse Questions').first().json; } catch(e) { data = $('Repeat Logic').first().json; }
const s = data.updatedSession;
return [{ json: {
  userId: s.userId, phoneNumber: s.phoneNumber, intentName: s.intentName,
  organizationId: s.organizationId, parentOrganizationId: s.parentOrganizationId,
  phase: s.phase || 'repeat', currentMainIndex: s.currentMainIndex,
  sectionName: s.sectionName, currentCycle: s.currentCycle, currentFieldIndex: s.currentFieldIndex,
  completedItems: typeof s.completedItems === 'string' ? s.completedItems : JSON.stringify(s.completedItems || []),
  currentItem: typeof s.currentItem === 'string' ? s.currentItem : JSON.stringify(s.currentItem || {}),
  collectedFields: typeof s.collectedFields === 'string' ? s.collectedFields : JSON.stringify(s.collectedFields || {}),
  generatedQuestions: typeof s.generatedQuestions === 'string' ? s.generatedQuestions : JSON.stringify(s.generatedQuestions || {}),
  createdAt: s.createdAt || new Date().toISOString()
} }];

const data = $('Repeat Logic').first().json;
const config = data.repeatConfig;
const phoneNumber = $('Execute Workflow Trigger').first().json.phoneNumber;
const opts = config.continueOptions || ['Yes', 'No'];
const payload = {
  messaging_product: "whatsapp", to: phoneNumber, type: "interactive",
  interactive: { type: "button", body: { text: config.continuePrompt || "Would you like to add another?" },
    action: { buttons: [
      { type: "reply", reply: { id: "__repeat_yes__", title: opts[0] || "Yes" } },
      { type: "reply", reply: { id: "__repeat_no__", title: opts[1] || "No" } }
    ]}}
};
return [{ json: { responseType: "interactive", message: config.continuePrompt, interactivePayload: payload } }];

let data;
try { data = $('Parse Questions').first().json; } catch(e) { data = $('Repeat Logic').first().json; }
const field = data.nextField;
const questions = data.genQuestions || {};
const question = questions[field.name] || field.description || 'Please provide ' + field.name;
const phoneNumber = $('Execute Workflow Trigger').first().json.phoneNumber;
const orgDoc = $('Fetch Org Doc').first().json;
const intent = (orgDoc.intents || []).find(i => i.name === $('Fetch Intent Session').first().json.intentName);
const repeatConfig = intent?.repeatSections?.[$('Fetch Intent Session').first().json.sectionName];
const param = (repeatConfig?.parameters || []).find(p => p.name === field.name);

if (!param || field.type === 'text') {
  return [{ json: { responseType: "text", message: question, needsAPI: false } }];
}

const optionsSource = param.optionsSource || 'static';

if (field.type === 'list_buttons' && optionsSource === 'api' && param.optionsConfig) {
  return [{ json: { responseType: "__needs_api__", message: question, needsAPI: true, optionsConfig: param.optionsConfig, fieldName: field.name, intentName: intent.name } }];
}

const opts = (param.options || []).map((o, i) => ({ id: typeof o === 'string' ? o : (o.id || String(i)), title: typeof o === 'string' ? o : (o.title || '') }));

if (field.type === 'options' && opts.length <= 3) {
  const btns = opts.map(o => ({ type: "reply", reply: { id: o.id, title: o.title.substring(0, 20) } }));
  return [{ json: { responseType: "interactive", message: question, needsAPI: false, interactivePayload: { messaging_product: "whatsapp", to: phoneNumber, type: "interactive", interactive: { type: "button", body: { text: question }, action: { buttons: btns } } } } }];
}

const PAGE_SIZE = 9; const needsP = opts.length > 10;
const rows = (needsP ? opts.slice(0, PAGE_SIZE) : opts).map(o => ({ id: o.id, title: o.title.substring(0, 24) }));
if (needsP) rows.push({ id: '__page__' + intent.name + '__' + field.name + '__2', title: '\u25B6 More options' });
return [{ json: { responseType: "interactive", message: question, needsAPI: false, interactivePayload: { messaging_product: "whatsapp", recipient_type: "individual", to: phoneNumber, type: "interactive", interactive: { type: "list", body: { text: question }, action: { button: "Select an option", sections: [{ rows }] } } } } }];

let r;
try { r = $('Build Field Response').first().json; } catch(e) { r = $('Build Continue Buttons').first().json; }
return [{ json: { responseType: r.responseType, message: r.message, interactivePayload: r.interactivePayload || undefined } }];

const d = $input.first().json;
const c = d.optionsConfig;
const orgDoc = $('Fetch Org Doc').first().json;
return [{ json: { url: c.url, method: c.method||'GET', headers: c.headers||{}, body: {...(c.body||{}), parentOrganizationId: orgDoc.parentOrganizationId}, mapping: c.mapping||{id:'id',title:'title'}, dataPath: c.dataPath||null, message: d.message, intentName: d.intentName, fieldName: d.fieldName } }];

const api = $input.first().json;
const p = $('Prep Repeat API').first().json;
let raw = api; if(p.dataPath){for(const k of p.dataPath.split('.'))raw=raw?.[k];}
if(!Array.isArray(raw)) raw = [];
const opts = raw.map(i => ({ id: String(i[p.mapping.id]||''), title: String(i[p.mapping.title]||'') }));
const ph = $('Execute Workflow Trigger').first().json.phoneNumber;
return [{ json: { phoneNumber: ph, intentName: p.intentName, fieldName: p.fieldName, options: JSON.stringify(opts), totalCount: opts.length, createdAt: new Date().toISOString(), message: p.message, resolvedOptions: opts } }];

const d = $('Map Repeat API').first().json;
const opts = d.resolvedOptions || []; const ph = d.phoneNumber;
const p = $('Prep Repeat API').first().json;
if(!opts.length) return [{ json: { responseType: "text", message: d.message } }];
const PS=9; const needsP=opts.length>10;
const rows = (needsP?opts.slice(0,PS):opts).map(o=>({id:o.id,title:o.title.substring(0,24)}));
if(needsP) rows.push({id:'__page__'+p.intentName+'__'+p.fieldName+'__2',title:'\u25B6 More options'});
return [{ json: { responseType: "interactive", message: d.message, interactivePayload: { messaging_product:"whatsapp", recipient_type:"individual", to:ph, type:"interactive", interactive:{type:"list",body:{text:d.message},action:{button:"Select an option",sections:[{rows}]}}} } }];

const data = $('Repeat Logic').first().json;
const subParams = data.subParams || [];
// Use the exact configured description verbatim as the question —
// no LLM rephrasing, so what the org types is exactly what the user sees.
const questions = Object.fromEntries(subParams.map(p => [p.name, p.description || p.name]));
const session = data.updatedSession;
session.generatedQuestions = JSON.stringify(questions);
return [{ json: { ...data, genQuestions: questions, updatedSession: session } }];
